  function handleMessage(msg) {
    let msgId;
    Object.keys(msg).includes('msgId') ? msgId = msg.msgId : msgId = 'noId';
    switch(msgId){
      case 'application_topic':
        handleApplicationTopic(msg);
        break;
      case 'error_state':
        handleFalldownDetectedTopic(msg);
        break;
